const (
	maxScriptLength = 16 * 1024
	scriptTimeout   = 100 * time.Millisecond
)

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM
// and returns the resulting discount amount.
//
// Security hardening:
//   - The order object is exposed as a single "order" variable instead of
//     injecting arbitrary globals.
//   - Script size is limited.
//   - Execution time is bounded using vm.Interrupt().
//   - Only finite, non-negative numeric results are accepted.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	if len(script) == 0 {
		return 0, errors.New("script cannot be empty")
	}
	if len(script) > maxScriptLength {
		return 0, fmt.Errorf("script too large: maximum %d bytes", maxScriptLength)
	}
	if order == nil {
		order = map[string]interface{}{}
	}

	vm := goja.New()

	// Expose order as a single object to avoid polluting globals or allowing
	// administrator-controlled keys to overwrite built-ins.
	if err := vm.Set("order", order); err != nil {
		return 0, fmt.Errorf("failed to set order object: %w", err)
	}

	// Bound execution time to reduce risk of infinite loops / CPU exhaustion.
	timer := time.AfterFunc(scriptTimeout, func() {
		vm.Interrupt(errors.New("script execution timed out"))
	})
	defer timer.Stop()

	result, err := vm.RunString(script)
	if err != nil {
		return 0, fmt.Errorf("script execution error: %w", err)
	}

	discount, err := valueToFloat64(result)
	if err != nil {
		return 0, err
	}
	if math.IsNaN(discount) || math.IsInf(discount, 0) {
		return 0, errors.New("script must return a finite number")
	}
	if discount < 0 {
		return 0, errors.New("script must return a non-negative discount")
	}

	return discount, nil
}

func valueToFloat64(v goja.Value) (float64, error) {
	if v == nil {
		return 0, errors.New("script must return a number, got nil")
	}

	exported := v.Export()
	switch n := exported.(type) {
	case float64:
		return n, nil
	case float32:
		return float64(n), nil
	case int:
		return float64(n), nil
	case int8:
		return float64(n), nil
	case int16:
		return float64(n), nil
	case int32:
		return float64(n), nil
	case int64:
		return float64(n), nil
	case uint:
		return float64(n), nil
	case uint8:
		return float64(n), nil
	case uint16:
		return float64(n), nil
	case uint32:
		return float64(n), nil
	case uint64:
